{
  "name": "SimplePrep",
  "description": "A modern interview preparation application featuring practice questions, video/audio recording, and AI-powered feedback.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState } from 'react';
import { Navbar } from './components/Navbar';
import { Home } from './components/Home';
import { Practice } from './components/Practice';
import { Recordings } from './components/Recordings';
import { View, Recording } from './types';

export default function App() {
  const [currentView, setCurrentView] = useState<View>(View.HOME);
  const [recordings, setRecordings] = useState<Recording[]>([]);

  const handleSaveRecording = (recording: Recording) => {
    setRecordings((prev) => [recording, ...prev]);
  };

  const renderView = () => {
    switch (currentView) {
      case View.HOME:
        return <Home onStart={() => setCurrentView(View.PRACTICE)} />;
      case View.PRACTICE:
        return <Practice onSaveRecording={handleSaveRecording} />;
      case View.RECORDINGS:
        return <Recordings recordings={recordings} />;
      default:
        return <Home onStart={() => setCurrentView(View.PRACTICE)} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col text-slate-900">
      <Navbar currentView={currentView} onNavigate={setCurrentView} />
      <main className="flex-grow">
        {renderView()}
      </main>
    </div>
  );
}

export enum View {
  HOME = 'HOME',
  PRACTICE = 'PRACTICE',
  RECORDINGS = 'RECORDINGS',
}

export enum QuestionCategory {
  UX_DESIGN = 'UX Design',
  DATA_ANALYTICS = 'Data Analytics',
  PROJECT_MANAGEMENT = 'Project Management',
  DIGITAL_MARKETING = 'Digital Marketing',
  IT_SUPPORT = 'IT Support',
  CYBERSECURITY = 'Cybersecurity',
  GENERAL = 'General',
}

export interface Question {
  id: string;
  text: string;
  category: QuestionCategory;
  type: 'Background' | 'Situational' | 'Technical';
}

export interface Recording {
  id: string;
  questionId: string;
  questionText: string;
  date: Date;
  transcript: string;
  type: 'Video' | 'Audio' | 'Text';
  durationSeconds?: number;
}

import { GoogleGenAI } from "@google/genai";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const getAiSuggestion = async (question: string): Promise<string> => {
  if (!apiKey) {
    return "API Key is missing. Please check your configuration.";
  }

  try {
    const prompt = `
      You are an expert interview coach. 
      The user is practicing for a job interview.

      Question: "${question}"

      Please provide a concise, structured "Ideal Answer" or a set of key "Talking Points" that the user should cover in their response. 
      Keep the tone professional and encouraging. 
      Limit the response to around 150 words.
      Format neatly.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });

    return response.text || "Sorry, I couldn't generate a suggestion at this time.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Unable to connect to AI service. Please try again later.";
  }
};

import React from 'react';
import { View } from '../types';
import { Layout, Video, Mic } from 'lucide-react';

interface NavbarProps {
