import React, { useState, useEffect, useRef } from 'react';
import { Question, Recording } from '../types';
import { Mic, Video, Keyboard, PlayCircle, StopCircle, RefreshCcw, Camera, Maximize, Edit2 } from 'lucide-react';

interface QuestionFlowProps {
  question: Question;
  onComplete: (recording: Recording) => void;
  dontAskRedo: boolean;
  setDontAskRedo: (val: boolean) => void;
}

type FlowState = 'READING' | 'INPUT_SELECTION' | 'RECORDING_VOICE' | 'PREVIEW_CAMERA' | 'RECORDING_CAMERA' | 'TYPING' | 'REVIEW' | 'REDO_CONFIRM';

export const QuestionFlow: React.FC<QuestionFlowProps> = ({ question, onComplete, dontAskRedo, setDontAskRedo }) => {
  const [flowState, setFlowState] = useState<FlowState>('READING');
  const [transcript, setTranscript] = useState('');
  const [cameraStream, setCameraStream] = useState<MediaStream | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const [nextRedoMode, setNextRedoMode] = useState<'voice' | 'camera' | 'typing' | null>(null);

  // Auto-read question on mount
  useEffect(() => {
    // Reset state when question changes
    setFlowState('READING');
    setTranscript('');

    const utter = new SpeechSynthesisUtterance(question.text);
    utter.rate = 1.0;
    utter.onend = () => {
       // Only advance if we are still in reading state (user hasn't interrupted)
       setFlowState(prev => prev === 'READING' ? 'INPUT_SELECTION' : prev);
    };

    // Small delay to ensure UI mounts
    setTimeout(() => {
        window.speechSynthesis.cancel(); // clear previous
        window.speechSynthesis.speak(utter);
    }, 500);

    return () => {
      window.speechSynthesis.cancel();
      stopCamera();
    };
  }, [question]);

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
      setCameraStream(stream);
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (e) {
      console.error("Camera access failed", e);
    }
  };

  const stopCamera = () => {
    if (cameraStream) {
      cameraStream.getTracks().forEach(t => t.stop());
      setCameraStream(null);
    }
  };

  useEffect(() => {
    if (flowState === 'PREVIEW_CAMERA' || flowState === 'RECORDING_CAMERA') {
      startCamera();
    } else {
      stopCamera();
    }
  }, [flowState]);

  const handleVoiceStart = () => {
    setFlowState('RECORDING_VOICE');
    // Simulate recording start
  };

  const handleVoiceDone = () => {
    setFlowState('REVIEW');
    setTranscript("I believe my experience aligns well because I have worked on similar projects involving large-scale React applications...");
  };

  const handleCameraStart = () => {
     setFlowState('RECORDING_CAMERA');
  };

  const handleCameraDone = () => {
    setFlowState('REVIEW');
    setTranscript("I believe my experience aligns well because I have worked on similar projects involving large-scale React applications...");
  };

  const handleTypingDone = () => {
    setFlowState('REVIEW');
  };

  const initiateRedo = (mode: 'voice' | 'camera' | 'typing') => {
    if (dontAskRedo) {
      performRedo(mode);
    } else {
      setNextRedoMode(mode);
      setFlowState('REDO_CONFIRM');
    }
  };

  const performRedo = (mode: 'voice' | 'camera' | 'typing') => {
    setTranscript('');
    // For simplicity, redo goes back to reading the question as per requirements "Return to the initial question state"
    // But then we need to know which mode to auto-select? 
    // The requirements say: "If User Selects Yes -> Return to the initial question state. System reads the question aloud again. Answer options reappear."
    // So we don't auto-select the mode. We just reset.
    setFlowState('READING');

    const utter = new SpeechSynthesisUtterance(question.text);
    utter.onend = () => setFlowState('INPUT_SELECTION');
    window.speechSynthesis.cancel();
    window.speechSynthesis.speak(utter);
  };

  return (
    <div className="max-w-3xl mx-auto px-4 py-8 flex flex-col min-h-[80vh]">

      {/* Question Card */}
      <div className="bg-white rounded-2xl p-8 mb-6 shadow-sm border border-slate-100">
        <span className={`
            inline-block px-2 py-1 rounded text-xs font-medium mb-4
            ${question.type === 'Background' ? 'bg-purple-100 text-purple-700' : 'bg-blue-100 text-blue-700'}
        `}>
            {question.type === 'Custom question' ? 'Custom question' : `${question.type} question`}
        </span>
        <h2 className="text-2xl text-slate-800 leading-snug">
          {question.text}
        </h2>
      </div>

      {/* Dynamic Area based on State */}
      <div className="flex-grow">

        {/* STATE: READING (Just showing question, waiting for TTS) */}
        {flowState === 'READING' && (
          <div className="flex justify-center pt-10">
            <div className="flex items-center space-x-2 text-slate-400 animate-pulse">
               <div className="w-2 h-2 bg-blue-600 rounded-full animate-bounce"></div>
               <div className="w-2 h-2 bg-blue-600 rounded-full animate-bounce delay-100"></div>
               <div className="w-2 h-2 bg-blue-600 rounded-full animate-bounce delay-200"></div>
               <span className="text-sm font-medium text-slate-500">Reading question...</span>
            </div>
          </div>
        )}

        {/* STATE: INPUT SELECTION */}
        {flowState === 'INPUT_SELECTION' && (
          <div className="bg-white rounded-2xl p-6 border border-slate-100 shadow-sm animate-fade-in">
             <h3 className="text-lg font-medium text-slate-800 mb-6">Answer</h3>
             <div className="flex space-x-4">
                <button 
                  onClick={handleVoiceStart}
                  className="p-4 rounded-xl border border-blue-200 text-blue-600 hover:bg-blue-50 transition-colors"
                >
                  <Mic className="w-6 h-6" />
                </button>
                <button 
                  onClick={() => setFlowState('PREVIEW_CAMERA')}
                  className="p-4 rounded-xl border border-blue-200 text-blue-600 hover:bg-blue-50 transition-colors"
                >
                  <Video className="w-6 h-6" />
                </button>
                <button 
                  onClick={() => setFlowState('TYPING')}
                  className="p-4 rounded-xl border border-blue-200 text-blue-600 hover:bg-blue-50 transition-colors"
                >
                  <Keyboard className="w-6 h-6" />
                </button>
             </div>
          </div>
        )}

        {/* STATE: RECORDING VOICE */}
        {flowState === 'RECORDING_VOICE' && (
          <div className="bg-white rounded-2xl p-6 border border-slate-100 shadow-sm">
             <div className="flex flex-col items-center justify-center py-12 space-y-6">
                <div className="w-24 h-24 bg-red-50 rounded-full flex items-center justify-center animate-pulse">
                   <Mic className="w-10 h-10 text-red-500" />
                </div>
                <p className="text-slate-500">Recording your answer...</p>
                <button 
                   onClick={handleVoiceDone}
                   className="px-8 py-3 bg-blue-600 text-white font-semibold rounded-full hover:bg-blue-700 transition-colors"
                >
                   Done
                </button>
             </div>
          </div>
        )}

        {/* STATE: CAMERA PREVIEW & RECORDING */}
        {(flowState === 'PREVIEW_CAMERA' || flowState === 'RECORDING_CAMERA') && (
          <div className="bg-white rounded-2xl overflow-hidden border border-slate-100 shadow-sm">
             <div className="aspect-video bg-black relative">
                <video ref={videoRef} autoPlay muted playsInline className="w-full h-full object-cover transform scale-x-[-1]" />
                {flowState === 'RECORDING_CAMERA' && (
                  <div className="absolute top-4 right-4 flex items-center space-x-2 bg-red-600/80 text-white px-3 py-1 rounded-full text-xs font-bold">
                     <div className="w-2 h-2 bg-white rounded-full animate-pulse"></div>
                     <span>REC</span>
                  </div>
                )}
             </div>
             <div className="p-6">
               {flowState === 'PREVIEW_CAMERA' ? (
                  <button 
                    onClick={handleCameraStart}
                    className="w-full py-3 bg-blue-600 text-white font-semibold rounded-lg hover:bg-blue-700 transition-colors"
                  >
                    Start
                  </button>
               ) : (
                  <button 
                    onClick={handleCameraDone}
                    className="w-full py-3 bg-red-600 text-white font-semibold rounded-lg hover:bg-red-700 transition-colors"
                  >
                    Done
                  </button>
               )}
             </div>
          </div>
        )}

        {/* STATE: TYPING */}
        {flowState === 'TYPING' && (
           <div className="bg-white rounded-2xl p-6 border border-slate-100 shadow-sm h-96 flex flex-col">
              <h3 className="text-lg font-medium text-slate-800 mb-4 flex items-center">
                <Keyboard className="w-5 h-5 mr-2" /> Your answer
              </h3>
              <textarea 
                 value={transcript}
                 onChange={(e) => setTranscript(e.target.value)}
                 className="flex-grow w-full resize-none border-none focus:ring-0 text-lg text-slate-700 placeholder:text-slate-300"
                 placeholder="Type your answer here..."
                 autoFocus
              />
              <div className="pt-4 border-t border-slate-100 flex justify-end">
                 <button 
                   onClick={handleTypingDone}
                   className="px-6 py-2 bg-blue-600 text-white rounded-full font-medium hover:bg-blue-700"
                 >
                   Done
                 </button>
              </div>
           </div>
        )}

        {/* STATE: REVIEW */}
        {flowState === 'REVIEW' && (
           <div className="bg-white rounded-2xl p-6 border border-slate-100 shadow-sm">
             <div className="flex items-center justify-between mb-4">
               <div className="flex items-center text-slate-800 font-medium">
                 <div className="mr-2"><Maximize className="w-4 h-4 rotate-45" /></div>
                 Your answer
               </div>
               <button className="text-blue-600 hover:bg-blue-50 p-2 rounded-lg">
                 <Edit2 className="w-4 h-4" />
               </button>
             </div>

             <div className="min-h-[100px] text-slate-600 leading-relaxed mb-6">
               {transcript}
             </div>

             <div className="pt-6 border-t border-slate-100 flex items-center justify-between">
                <div>
                   <p className="text-xs font-semibold text-slate-500 uppercase tracking-wide mb-3">Redo</p>
                   <div className="flex space-x-2">
                      <button onClick={() => initiateRedo('voice')} className="p-2 border border-slate-200 rounded-lg text-blue-600 hover:bg-slate-50">
                        <Mic className="w-5 h-5" />
                      </button>
                      <button onClick={() => initiateRedo('camera')} className="p-2 border border-slate-200 rounded-lg text-blue-600 hover:bg-slate-50">
                        <Video className="w-5 h-5" />
                      </button>
                      <button onClick={() => initiateRedo('typing')} className="p-2 border border-slate-200 rounded-lg text-blue-600 hover:bg-slate-50">
                         <Maximize className="w-5 h-5" /> 
                         {/* Using Maximize as a placeholder for the text box icon in screenshot */}
                      </button>
                   </div>
                </div>

                <button className="p-2 border border-slate-200 rounded-lg text-blue-600 hover:bg-slate-50">
                  <RefreshCcw className="w-5 h-5" />
                </button>
             </div>
           </div>
        )}

        {/* STATE: REDO CONFIRMATION (Overlay or In-place) */}
        {flowState === 'REDO_CONFIRM' && (
           <div className="mt-4 bg-white rounded-2xl p-8 border border-slate-100 shadow-lg animate-fade-in-up">
              <h3 className="text-xl font-semibold text-slate-900 mb-2">Redo your answer?</h3>
              <p className="text-slate-600 mb-6">This will erase your current answer. Would you like to redo it?</p>

              <div className="flex items-center mb-8">
                 <input 
                   type="checkbox" 
                   id="dontAsk" 
                   className="w-4 h-4 text-blue-600 rounded border-slate-300 focus:ring-blue-500"
                   checked={dontAskRedo}
                   onChange={(e) => setDontAskRedo(e.target.checked)}
                 />
                 <label htmlFor="dontAsk" className="ml-2 text-sm text-slate-600">Don't ask again</label>
              </div>

              <div className="flex justify-end space-x-4">
                 <button 
                   onClick={() => setFlowState('REVIEW')}
                   className="px-4 py-2 text-slate-600 font-medium hover:text-slate-900"
                 >
                   Cancel
                 </button>
                 <button 
                   onClick={() => nextRedoMode && performRedo(nextRedoMode)}
                   className="px-6 py-2 bg-blue-50 text-blue-700 font-semibold rounded-lg border border-blue-100 hover:bg-blue-100"
                 >
                   Yes
                 </button>
              </div>
           </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Navbar } from './components/Navbar';
import { FieldSelection } from './components/FieldSelection';
import { Practice } from './components/Practice';
import { QuestionFlow } from './components/QuestionFlow';
import { View, QuestionCategory, Question, Recording } from './types';

// Mock Data
const QUESTIONS: Record<string, Question[]> = {
  [QuestionCategory.UX_DESIGN]: [
    { id: '1', text: 'Please tell me why would you be a good fit for this role?', category: QuestionCategory.UX_DESIGN, type: 'Background' },
    { id: '2', text: 'How does your experience align with the position you applied?', category: QuestionCategory.UX_DESIGN, type: 'Background' },
    { id: '3', text: 'Please share a time when you set a goal for yourself and achieved it. How did you go about that?', category: QuestionCategory.UX_DESIGN, type: 'Situation' },
    { id: '4', text: 'When would you conduct a usability study?', category: QuestionCategory.UX_DESIGN, type: 'Technical' },
    { id: '5', text: 'How do you measure success?', category: QuestionCategory.UX_DESIGN, type: 'Custom question' },
  ],
  // Fallback for others
  [QuestionCategory.ENGINEERING]: [
     { id: 'e1', text: 'Explain the CAP theorem.', category: QuestionCategory.ENGINEERING, type: 'Technical' }
  ]
};

export default function App() {
  const [history, setHistory] = useState<View[]>([View.FIELD_SELECTION]);
  const [currentViewIndex, setCurrentViewIndex] = useState(0);

  const [selectedCategory, setSelectedCategory] = useState<QuestionCategory | null>(null);
  const [selectedQuestion, setSelectedQuestion] = useState<Question | null>(null);
  const [dontAskRedo, setDontAskRedo] = useState(false);

  const currentView = history[currentViewIndex];

  const navigateTo = (view: View) => {
    const newHistory = history.slice(0, currentViewIndex + 1);
    newHistory.push(view);
    setHistory(newHistory);
    setCurrentViewIndex(newHistory.length - 1);
  };

  const handleBack = () => {
    if (currentViewIndex > 0) {
      setCurrentViewIndex(prev => prev - 1);
    }
  };

  const handleForward = () => {
    if (currentViewIndex < history.length - 1) {
      setCurrentViewIndex(prev => prev + 1);
    }
  };

  const handleSelectCategory = (cat: QuestionCategory) => {
    setSelectedCategory(cat);
  };

  const handleStartPractice = () => {
    // Start with the first question of the selected category
    const questions = QUESTIONS[selectedCategory!] || QUESTIONS[QuestionCategory.UX_DESIGN];
    setSelectedQuestion(questions[0]);
    navigateTo(View.QUESTION_FLOW);
  };

  const handleSeeAllQuestions = () => {
    navigateTo(View.ALL_QUESTIONS);
  };

  const handleSelectQuestion = (q: Question) => {
    setSelectedQuestion(q);
    navigateTo(View.QUESTION_FLOW);
  };

  const renderView = () => {
    switch (currentView) {
      case View.FIELD_SELECTION:
        return (
          <FieldSelection 
            selectedCategory={selectedCategory}
            onSelectCategory={handleSelectCategory}
            onStartPractice={handleStartPractice}
            onSeeAllQuestions={handleSeeAllQuestions}
          />
        );
      case View.ALL_QUESTIONS:
        return (
          <Practice 
            category={selectedCategory!}
            questions={QUESTIONS[selectedCategory!] || QUESTIONS[QuestionCategory.UX_DESIGN]}
            onSelectQuestion={handleSelectQuestion}
          />
        );
      case View.QUESTION_FLOW:
        return (
          <QuestionFlow 
            question={selectedQuestion!}
            onComplete={(rec) => console.log(rec)}
            dontAskRedo={dontAskRedo}
            setDontAskRedo={setDontAskRedo}
          />
        );
      default:
        return <div>Unknown View</div>;
    }
  };

  return (
    <div className="min-h-screen bg-white text-slate-900 flex flex-col">
      <Navbar 
        onBack={handleBack} 
        onForward={handleForward}
        canGoBack={currentViewIndex > 0}
        canGoForward={currentViewIndex < history.length - 1}
      />
      <main className="flex-grow">
        {renderView()}
      </main>
    </div>
  );
}

