      <div className="w-full max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 flex justify-between items-center">
        <button 
          onClick={onBack} 
          onMouseEnter={playHoverSound}
          disabled={!canGoBack}
          className={`
            w-12 h-12 flex items-center justify-center rounded-[25%] transition-all
            ${canGoBack 
              ? 'bg-[#D9D9D9]/30 hover:bg-[#D9D9D9]/60 text-black cursor-pointer' 
              : 'bg-[#D9D9D9]/10 text-black/20 cursor-default'}
          `}
        >
          <ArrowLeft className="w-6 h-6" />
        </button>

        <button 
          onClick={onForward}
          onMouseEnter={playHoverSound}
          disabled={!canGoForward}
          className={`
            w-12 h-12 flex items-center justify-center rounded-[25%] transition-all
            ${canGoForward 
              ? 'bg-[#D9D9D9]/30 hover:bg-[#D9D9D9]/60 text-black cursor-pointer' 
              : 'bg-[#D9D9D9]/10 text-black/20 cursor-default'}
          `}
        >
          <ArrowRight className="w-6 h-6" />
        </button>
      </div>
    </nav>
  );
};

