import React, { useState, useEffect, useRef } from 'react';
import { Question, Recording } from '../types';
import { Mic, Video, Keyboard, PlayCircle, StopCircle, RefreshCcw, Camera, Maximize, Edit2, Info } from 'lucide-react';
import { playHoverSound } from '../utils/sound';

interface QuestionFlowProps {
  question: Question;
  onComplete: (recording: Recording) => void;
  dontAskRedo: boolean;
  setDontAskRedo: (val: boolean) => void;
}

type FlowState = 'READING' | 'INPUT_SELECTION' | 'RECORDING_VOICE' | 'PREVIEW_CAMERA' | 'RECORDING_CAMERA' | 'TYPING' | 'REVIEW' | 'REDO_CONFIRM';

export const QuestionFlow: React.FC<QuestionFlowProps> = ({ question, onComplete, dontAskRedo, setDontAskRedo }) => {
  const [flowState, setFlowState] = useState<FlowState>('READING');
  const [transcript, setTranscript] = useState('');
  const [cameraStream, setCameraStream] = useState<MediaStream | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const [nextRedoMode, setNextRedoMode] = useState<'voice' | 'camera' | 'typing' | null>(null);

  // Speech Recognition Refs
  const recognitionRef = useRef<any>(null);

  // Initialize Speech Recognition
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = true;
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = 'en-US';

      recognitionRef.current.onresult = (event: any) => {
        let interimTranscript = '';
        let finalTranscript = '';

        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) {
            finalTranscript += event.results[i][0].transcript;
          } else {
            interimTranscript += event.results[i][0].transcript;
          }
        }

        // Append to existing transcript for simulation of continuous flow or just use current session
        // Here we just update the live view. For a full app we'd manage state more carefully to not overwrite manually edited text.
        setTranscript(prev => {
             // Simple logic: if we just started, replace. If we are appending, we need more robust logic. 
             // For this demo, let's just show what's being said now plus what was there.
             // Actually, speech API `continuous` usually gives the whole session if not stopped. 
             // Let's just use the latest results.
             return finalTranscript + interimTranscript;
        });
      };

      recognitionRef.current.onerror = (event: any) => {
        console.error("Speech recognition error", event.error);
      };
    }
  }, []);

  const startListening = () => {
    if (recognitionRef.current) {
      try {
        recognitionRef.current.start();
      } catch (e) {
        // Already started
      }
    }
  };

  const stopListening = () => {
    if (recognitionRef.current) {
      try {
        recognitionRef.current.stop();
      } catch (e) {
        // Already stopped
      }
    }
  };

  // Auto-read question on mount
  useEffect(() => {
    setFlowState('READING');
    setTranscript('');

    const utter = new SpeechSynthesisUtterance(question.text);
    utter.rate = 1.0;
    utter.onend = () => {
       setFlowState(prev => prev === 'READING' ? 'INPUT_SELECTION' : prev);
    };

    setTimeout(() => {
        window.speechSynthesis.cancel();
        window.speechSynthesis.speak(utter);
    }, 500);

    return () => {
      window.speechSynthesis.cancel();
      stopCamera();
      stopListening();
    };
  }, [question]);

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
      setCameraStream(stream);
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (e) {
      console.error("Camera access failed", e);
    }
  };

  const stopCamera = () => {
    if (cameraStream) {
      cameraStream.getTracks().forEach(t => t.stop());
      setCameraStream(null);
    }
  };

  useEffect(() => {
    if (flowState === 'PREVIEW_CAMERA' || flowState === 'RECORDING_CAMERA') {
      startCamera();
    } else {
      stopCamera();
    }

    if (flowState === 'RECORDING_VOICE') {
        startListening();
    } else {
        stopListening();
    }
  }, [flowState]);

  const handleVoiceStart = () => {
    setFlowState('RECORDING_VOICE');
  };

  const handleVoiceDone = () => {
    setFlowState('REVIEW');
    stopListening();
    // If transcript is empty (no mic support), fill dummy
    if (!transcript) {
        setTranscript("I believe my experience aligns well because I have worked on similar projects involving large-scale React applications and ensuring accessibility standards...");
    }
  };

  const handleCameraStart = () => {
     setFlowState('RECORDING_CAMERA');
  };

  const handleCameraDone = () => {
    setFlowState('REVIEW');
  };

  const handleTypingDone = () => {
    setFlowState('REVIEW');
  };

  const initiateRedo = (mode: 'voice' | 'camera' | 'typing') => {
    if (dontAskRedo) {
      performRedo(mode);
    } else {
      setNextRedoMode(mode);
      setFlowState('REDO_CONFIRM');
    }
  };

  const performRedo = (mode: 'voice' | 'camera' | 'typing') => {
    setTranscript('');
    setFlowState('READING');
    const utter = new SpeechSynthesisUtterance(question.text);
    utter.onend = () => setFlowState('INPUT_SELECTION');
    window.speechSynthesis.cancel();
    window.speechSynthesis.speak(utter);
  };

  // Icon container style to match "Your answer" size
  const iconContainerClass = "w-14 h-14 rounded-2xl border border-slate-200 flex items-center justify-center hover:bg-slate-50 transition-colors text-slate-700";

  return (
    <div className="max-w-3xl mx-auto px-4 py-8 flex flex-col min-h-[80vh]">

      {/* Question Card */}
      <div className="bg-white rounded-2xl p-8 mb-6 shadow-sm border border-slate-100">
        <span className={`
            inline-flex items-center px-2 py-1 rounded text-xs font-medium mb-4
            ${question.type === 'Background' ? 'bg-purple-100 text-purple-700' : 
              question.type === 'Custom question' ? 'bg-yellow-100 text-yellow-800' :
              'bg-blue-100 text-blue-700'}
        `}>
            <Info className="w-3 h-3 mr-1" />
            {question.type === 'Custom question' ? 'Custom question' : `${question.type} question`}
        </span>
        <h2 className="text-2xl text-slate-800 leading-snug">
          {question.text}
        </h2>
      </div>

      {/* Dynamic Area based on State */}
      <div className="flex-grow">

        {/* STATE: READING */}
        {flowState === 'READING' && (
          <div className="flex justify-center pt-10">
            <div className="flex items-center space-x-2 text-slate-400 animate-pulse">
               <div className="w-2 h-2 bg-blue-600 rounded-full animate-bounce"></div>
               <div className="w-2 h-2 bg-blue-600 rounded-full animate-bounce delay-100"></div>
               <div className="w-2 h-2 bg-blue-600 rounded-full animate-bounce delay-200"></div>
               <span className="text-sm font-medium text-slate-500">Reading question...</span>
            </div>
          </div>
        )}

        {/* STATE: INPUT SELECTION */}
        {flowState === 'INPUT_SELECTION' && (
          <div className="bg-white rounded-2xl p-6 border border-slate-100 shadow-sm animate-fade-in">
             <div className="flex items-center justify-between mb-6">
                <h3 className="text-lg font-medium text-slate-800 flex items-center">
                    <div className="mr-3 w-6 h-6 flex items-center justify-center">
                        <svg className="w-6 h-6 text-slate-800" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h8m-8 6h16" />
                        </svg>
                    </div>
                    Your answer
                </h3>
                <div className="w-10 h-10 border border-slate-200 rounded-xl flex items-center justify-center text-blue-600">
                    <Edit2 className="w-5 h-5" />
                </div>
             </div>

             <div className="flex space-x-4 pl-9">
                <button 
                  onClick={handleVoiceStart}
                  onMouseEnter={playHoverSound}
                  className={iconContainerClass}
                >
                  <Mic className="w-6 h-6" />
                </button>
                <button 
                  onClick={() => setFlowState('PREVIEW_CAMERA')}
                  onMouseEnter={playHoverSound}
                  className={iconContainerClass}
                >
                  <Video className="w-6 h-6" />
                </button>
                <button 
                  onClick={() => setFlowState('TYPING')}
                  onMouseEnter={playHoverSound}
                  className={iconContainerClass}
                >
                  <Keyboard className="w-6 h-6" />
                </button>
             </div>
          </div>
        )}

        {/* STATE: RECORDING VOICE (Real-time transcription) */}
        {flowState === 'RECORDING_VOICE' && (
          <div className="bg-white rounded-2xl p-6 border border-slate-100 shadow-sm">
             <div className="mb-6 min-h-[100px] text-lg text-slate-700 leading-relaxed">
                {transcript || <span className="text-slate-300">Listening... start speaking to see transcription.</span>}
             </div>
             <div className="flex justify-end">
                <button 
                   onClick={handleVoiceDone}
                   className="px-8 py-3 bg-blue-600 text-white font-semibold rounded-[20px] hover:bg-blue-700 transition-colors shadow-md"
                >
                   Done
                </button>
             </div>
          </div>
        )}

        {/* STATE: CAMERA PREVIEW & RECORDING */}
        {(flowState === 'PREVIEW_CAMERA' || flowState === 'RECORDING_CAMERA') && (
          <div className="bg-white rounded-2xl overflow-hidden border border-slate-100 shadow-sm">
             <div className="aspect-video bg-black relative">
                <video ref={videoRef} autoPlay muted playsInline className="w-full h-full object-cover transform scale-x-[-1]" />
                {flowState === 'RECORDING_CAMERA' && (
                  <div className="absolute top-4 right-4 flex items-center space-x-2 bg-red-600/80 text-white px-3 py-1 rounded-full text-xs font-bold">
                     <div className="w-2 h-2 bg-white rounded-full animate-pulse"></div>
                     <span>REC</span>
                  </div>
                )}
             </div>
             <div className="p-6">
               {flowState === 'PREVIEW_CAMERA' ? (
                  <button 
                    onClick={handleCameraStart}
                    className="w-full py-3 bg-blue-600 text-white font-semibold rounded-[20px] hover:bg-blue-700 transition-colors"
                  >
                    Start
                  </button>
               ) : (
                  <button 
                    onClick={handleCameraDone}
                    className="w-full py-3 bg-red-600 text-white font-semibold rounded-[20px] hover:bg-red-700 transition-colors"
                  >
                    Done
                  </button>
               )}
             </div>
          </div>
        )}

        {/* STATE: TYPING */}
        {flowState === 'TYPING' && (
           <div className="bg-white rounded-2xl p-6 border border-slate-100 shadow-sm h-96 flex flex-col">
              <h3 className="text-lg font-medium text-slate-800 mb-4 flex items-center">
                <Keyboard className="w-5 h-5 mr-2" /> Your answer
              </h3>
              <textarea 
                 value={transcript}
                 onChange={(e) => setTranscript(e.target.value)}
                 className="flex-grow w-full resize-none border-none focus:ring-0 text-lg text-slate-700 placeholder:text-slate-300"
                 placeholder="Type your answer here..."
                 autoFocus
              />
              <div className="pt-4 border-t border-slate-100 flex justify-end">
                 <button 
                   onClick={handleTypingDone}
                   className="px-6 py-2 bg-blue-600 text-white rounded-[20px] font-medium hover:bg-blue-700"
                 >
                   Done
                 </button>
              </div>
           </div>
        )}

        {/* STATE: REVIEW */}
        {flowState === 'REVIEW' && (
           <div className="bg-white rounded-2xl p-6 border border-slate-100 shadow-sm">
             <div className="flex items-center justify-between mb-4">
               <div className="flex items-center text-slate-800 font-medium">
                 <div className="mr-3 w-6 h-6 flex items-center justify-center">
                    <svg className="w-6 h-6 text-slate-800" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h8m-8 6h16" />
                    </svg>
                 </div>
                 Your answer
               </div>
               <button className="text-blue-600 border border-slate-200 p-2 rounded-xl hover:bg-blue-50 transition-colors">
                 <Edit2 className="w-5 h-5" />
               </button>
             </div>

             <div className="min-h-[100px] text-slate-600 leading-relaxed mb-6 pl-9">
               {transcript}
             </div>

             <div className="pt-6 border-t border-slate-100 flex items-center justify-between pl-9">
                <div className="flex items-center space-x-4">
                   <div className="flex flex-col">
                       <span className="text-xs font-semibold text-slate-500 uppercase tracking-wide mb-2">Redo</span>
                       <div className="flex space-x-2">
                          <button onMouseEnter={playHoverSound} onClick={() => initiateRedo('voice')} className={iconContainerClass}>
                            <Mic className="w-6 h-6" />
                          </button>
                          <button onMouseEnter={playHoverSound} onClick={() => initiateRedo('camera')} className={iconContainerClass}>
                            <Video className="w-6 h-6" />
                          </button>
                          <button onMouseEnter={playHoverSound} onClick={() => initiateRedo('typing')} className={iconContainerClass}>
                             <Keyboard className="w-6 h-6" /> 
                          </button>
                       </div>
                   </div>
                </div>

                <button onMouseEnter={playHoverSound} className={iconContainerClass}>
                  <RefreshCcw className="w-6 h-6" />
                </button>
             </div>
           </div>
        )}

        {/* STATE: REDO CONFIRMATION */}
        {flowState === 'REDO_CONFIRM' && (
           <div className="mt-4 bg-white rounded-2xl p-8 border border-slate-100 shadow-lg animate-fade-in-up">
              <h3 className="text-xl font-semibold text-slate-900 mb-2">Redo your answer?</h3>
              <p className="text-slate-600 mb-6">This will erase your current answer. Would you like to redo it?</p>

              <div className="flex items-center mb-8">
                 <input 
                   type="checkbox" 
                   id="dontAsk" 
                   className="w-4 h-4 text-blue-600 rounded border-slate-300 focus:ring-blue-500"
                   checked={dontAskRedo}
                   onChange={(e) => setDontAskRedo(e.target.checked)}
                 />
                 <label htmlFor="dontAsk" className="ml-2 text-sm text-slate-600">Don't ask again</label>
              </div>

              <div className="flex justify-end space-x-4">
                 <button 
                   onClick={() => setFlowState('REVIEW')}
                   className="px-4 py-2 text-slate-600 font-medium hover:text-slate-900"
                 >
                   Cancel
                 </button>
                 <button 
                   onClick={() => nextRedoMode && performRedo(nextRedoMode)}
                   className="px-6 py-2 bg-blue-50 text-blue-700 font-semibold rounded-lg border border-blue-100 hover:bg-blue-100"
                 >
                   Yes
                 </button>
              </div>
           </div>
        )}
      </div>
    </div>
  );
};

